#include <bits/stdc++.h>
#define int long long
using namespace std;

//定义所需变量(一部分)
int n , m;
char c[505][505];
int pos_x1 , pos_y1 , pos_x2 , pos_y2;
int dx[] = { 0 , 0 , 1 , -1 };
int dy[] = { 1 , -1 , 0 , 0 };

//BFS广搜函数
int bfs() {

	//初始赋值
	deque < pair < int , int > > q;
	int d[505][505];
	memset( d , -1 , sizeof( d ) );
	d[pos_x1][pos_y1] = 0;
	q.push_front( { pos_x1 , pos_y1 } );

	//求最短路
	while( q.size() ) {
		int x = q.front().first;
		int y = q.front().second;
		q.pop_front();
		for( int i = 0 ; i < 4 ; i++ ) {
			int _x = x + dx[i];
			int _y = y + dy[i];
			if( _x < 0 || _y < 0 || _x >= n || _y >= m ) {
				continue;
			}
			if( d[_x][_y] >= 0 ) {
				continue;
			}
			if( c[_x][_y] == c[x][y] ) { 
				q.push_front( { _x , _y } );
				d[_x][_y] = d[x][y];
			} else {
				q.push_back( { _x , _y } );
				d[_x][_y] = d[x][y] + 1;
			}
		}
	}
	return d[pos_x2][pos_y2];
}

//为了避免主函数过于长，所以我们将本来应该写在主函数里的搬了过来
void excute() {

	//输入矩阵，输入起点和终点
	for( int i = 0 ; i < n ; i++ ) {
		for( int j = 0 ; j < m ; j++ ) {
			cin >> c[i][j];
		}
	}
	cin >> pos_x1 >> pos_y1 >> pos_x2 >> pos_y2;

	//输出BFS广搜的结果
    cout << bfs() << '\n';
    return;
}

signed main() {

	//输入棋盘的大小，因为是多测，但是我们不知道要测几组，所以我们先写一个
	cin >> n >> m;

	//循环完成题目给出的任务
	while( n && m ) {
		excute();
		cin >> n >> m;
	}
	return 0;
}
